impl AgentBackend for CodexBackend {
    fn launch(&mut self, request: AgentLaunch) -> Result<AgentSession, AgentError> {
        let invocation = self.build_launch_invocation(&request);
        let output = self.run_invocation_streaming(&invocation, Some(&request.id), &mut |_| {})?;
        self.record_launch_output(request, output)
    }

    fn send(&mut self, agent_id: &AgentId, prompt: &str) -> Result<ChatMessage, AgentError> {
        let invocation = self.build_send_invocation(agent_id, prompt)?;
        let output = self.run_invocation_streaming(&invocation, Some(agent_id), &mut |_| {})?;
        let reply = parse_codex_output(&output).agent_reply.unwrap_or(output);
        let message = ChatMessage::new(MessageRole::Agent, reply);
        self.record_agent_exchange(agent_id, prompt, message.clone())?;
        Ok(message)
    }

    fn execute_command(
        &mut self,
        agent_id: &AgentId,
        command: &str,
    ) -> Result<ChatMessage, AgentError> {
        if let Some(parsed) = parse_backend_command(command)
            && parsed.token == "status"
        {
            let message =
                ChatMessage::new(MessageRole::Agent, self.render_status_command(agent_id));
            self.record_agent_exchange(agent_id, command, message.clone())?;
            return Ok(message);
        }

        let invocation = self.build_command_invocation(agent_id, command)?;
        let output = self.run_invocation_streaming(&invocation, Some(agent_id), &mut |_| {})?;
        let reply = parse_codex_output(&output).agent_reply.unwrap_or(output);
        let message = ChatMessage::new(MessageRole::Agent, reply);
        self.record_agent_exchange(agent_id, command, message.clone())?;
        Ok(message)
    }

    fn shutdown_handle(&self) -> AgentShutdownHandle {
        self.shutdown.clone()
    }

    fn interrupt(&mut self, agent_id: &AgentId) -> Result<(), AgentError> {
        let pid = self
            .state
            .lock()
            .expect("codex backend state mutex poisoned")
            .active_processes
            .get(agent_id)
            .copied();
        if let Some(pid) = pid {
            let _ = self.shutdown.terminate_process(pid);
        }
        Ok(())
    }

    fn launch_streaming(
        &mut self,
        request: AgentLaunch,
        sink: &mut dyn FnMut(AgentStreamEvent),
    ) -> Result<AgentSession, AgentError> {
        let invocation = self.build_launch_invocation(&request);
        let output = self.run_invocation_streaming(&invocation, Some(&request.id), sink)?;
        self.record_launch_output(request, output)
    }

    fn send_streaming(
        &mut self,
        agent_id: &AgentId,
        prompt: &str,
        sink: &mut dyn FnMut(AgentStreamEvent),
    ) -> Result<ChatMessage, AgentError> {
        let invocation = self.build_send_invocation(agent_id, prompt)?;
        let output = self.run_invocation_streaming(&invocation, Some(agent_id), sink)?;
        let reply = parse_codex_output(&output).agent_reply.unwrap_or(output);
        let message = ChatMessage::new(MessageRole::Agent, reply);
        self.record_agent_exchange(agent_id, prompt, message.clone())?;
        Ok(message)
    }

    fn execute_command_streaming(
        &mut self,
        agent_id: &AgentId,
        command: &str,
        sink: &mut dyn FnMut(AgentStreamEvent),
    ) -> Result<ChatMessage, AgentError> {
        if let Some(parsed) = parse_backend_command(command)
            && parsed.token == "status"
        {
            let text = self.render_status_command(agent_id);
            sink(AgentStreamEvent::AgentMessage(text.clone()));
            let message = ChatMessage::new(MessageRole::Agent, text);
            self.record_agent_exchange(agent_id, command, message.clone())?;
            return Ok(message);
        }

        let invocation = self.build_command_invocation(agent_id, command)?;
        let output = self.run_invocation_streaming(&invocation, Some(agent_id), sink)?;
        let reply = parse_codex_output(&output).agent_reply.unwrap_or(output);
        let message = ChatMessage::new(MessageRole::Agent, reply);
        self.record_agent_exchange(agent_id, command, message.clone())?;
        Ok(message)
    }
}

