fn fork_invocation(
    &self,
    resume_id: &str,
    prompt: &str,
) -> Result<CodexInvocation, AgentError> {
    let mut args = vec![
        "--cd".to_string(),
        self.config.project_dir.display().to_string(),
        "--sandbox".to_string(),
        self.config.sandbox.as_codex_arg().to_string(),
        "--ask-for-approval".to_string(),
        "never".to_string(),
    ];
    if let Some(model) = &self.config.model {
        args.push("--model".to_string());
        args.push(model.clone());
    }
    args.extend(["fork".to_string(), resume_id.to_string()]);
    if !prompt.is_empty() {
        args.push(prompt.to_string());
    }
    Ok(CodexInvocation {
        program: self.config.binary.clone(),
        args,
        stdin: String::new(),
    })
}

fn record_agent_exchange(
    &self,
    agent_id: &AgentId,
    user_text: &str,
    message: ChatMessage,
) -> Result<(), AgentError> {
    let mut state = self
        .state
        .lock()
        .expect("codex backend state mutex poisoned");
    if let Some(session) = state.sessions.get_mut(agent_id) {
        session.push_message(MessageRole::User, user_text);
    } else {
        state.sessions.insert(
            agent_id.clone(),
            AgentSession::new(AgentLaunch::new(
                agent_id.clone(),
                AgentKind::Codex,
                "unknown",
                user_text,
            )),
        );
    }
    let session = state
        .sessions
        .get_mut(agent_id)
        .ok_or_else(|| AgentError::UnknownSession(agent_id.clone()))?;
    session.messages.push(message);
    Ok(())
}

